import React from 'react';
import { 
  Users, 
  Wallet, 
  AlertCircle, 
  TrendingUp,
  Sparkles
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell
} from 'recharts';
import { Student, FeeRecord, PaymentStatus, DashboardStats } from '../types';
import { getFinancialInsights } from '../services/geminiService';

interface DashboardProps {
  students: Student[];
  fees: FeeRecord[];
}

const Dashboard: React.FC<DashboardProps> = ({ students, fees }) => {
  const [aiInsights, setAiInsights] = React.useState<string | null>(null);
  const [isLoadingInsights, setIsLoadingInsights] = React.useState(false);

  const stats: DashboardStats = React.useMemo(() => {
    const totalCollected = fees.reduce((sum, f) => sum + f.paidAmount, 0);
    const totalPending = fees.reduce((sum, f) => sum + (f.totalAmount - f.paidAmount), 0);
    const pendingCount = fees.filter(f => f.status !== PaymentStatus.PAID).length;

    return {
      totalStudents: students.length,
      totalCollected,
      totalPending,
      pendingCount
    };
  }, [students, fees]);

  const chartData = [
    { name: 'Jan', collected: 4000, pending: 2400 },
    { name: 'Feb', collected: 3000, pending: 1398 },
    { name: 'Mar', collected: 2000, pending: 9800 },
    { name: 'Apr', collected: 2780, pending: 3908 },
    { name: 'May', collected: 1890, pending: 4800 },
    { name: 'Jun', collected: 2390, pending: 3800 },
  ];

  const pieData = [
    { name: 'Paid', value: fees.filter(f => f.status === PaymentStatus.PAID).length },
    { name: 'Partial', value: fees.filter(f => f.status === PaymentStatus.PARTIAL).length },
    { name: 'Unpaid', value: fees.filter(f => f.status === PaymentStatus.UNPAID).length },
  ];

  const COLORS = ['#2563eb', '#f59e0b', '#ef4444'];

  const handleGetInsights = async () => {
    setIsLoadingInsights(true);
    const insights = await getFinancialInsights(students, fees);
    setAiInsights(insights);
    setIsLoadingInsights(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Financial Overview</h1>
          <p className="text-slate-500">Welcome back, here's what's happening today.</p>
        </div>
        <button 
          onClick={handleGetInsights}
          disabled={isLoadingInsights}
          className="flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-blue-600 text-white px-5 py-2.5 rounded-xl font-medium hover:shadow-lg hover:shadow-blue-500/30 transition-all disabled:opacity-50"
        >
          <Sparkles size={18} />
          {isLoadingInsights ? 'Generating Insights...' : 'Get AI Financial Insights'}
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          label="Total Students" 
          value={stats.totalStudents.toString()} 
          icon={Users} 
          color="blue"
          trend="+3% from last month"
        />
        <StatCard 
          label="Collected Fees" 
          value={`$${stats.totalCollected.toLocaleString()}`} 
          icon={Wallet} 
          color="green"
          trend="+12% from last month"
        />
        <StatCard 
          label="Pending Amount" 
          value={`$${stats.totalPending.toLocaleString()}`} 
          icon={AlertCircle} 
          color="amber"
          trend="-5% from last month"
        />
        <StatCard 
          label="Payment Ratio" 
          value={`${Math.round((stats.totalCollected / (stats.totalCollected + stats.totalPending || 1)) * 100)}%`} 
          icon={TrendingUp} 
          color="indigo"
          trend="Healthy"
        />
      </div>

      {aiInsights && (
        <div className="bg-white border border-blue-100 rounded-2xl p-6 shadow-sm">
          <div className="flex items-center gap-2 mb-4 text-blue-700 font-bold">
            <Sparkles size={20} />
            <h2>AI Assistant Insights</h2>
          </div>
          <div className="prose prose-sm max-w-none text-slate-600 whitespace-pre-line">
            {aiInsights}
          </div>
          <button 
            onClick={() => setAiInsights(null)}
            className="mt-4 text-xs font-semibold text-slate-400 hover:text-slate-600"
          >
            Dismiss Insights
          </button>
        </div>
      )}

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="font-bold text-slate-800 mb-6">Revenue Trend</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f8fafc'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="collected" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={32} />
                <Bar dataKey="pending" fill="#e2e8f0" radius={[4, 4, 0, 0]} barSize={32} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <h3 className="font-bold text-slate-800 mb-6">Collection Status</h3>
          <div className="h-64 flex flex-col items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="w-full space-y-3 mt-4">
              {pieData.map((item, idx) => (
                <div key={item.name} className="flex items-center justify-between text-sm">
                  <div className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[idx]}}></div>
                    <span className="text-slate-500">{item.name}</span>
                  </div>
                  <span className="font-semibold text-slate-800">{item.value} Records</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{label: string, value: string, icon: any, color: string, trend: string}> = ({ label, value, icon: Icon, color, trend }) => {
  const colors: Record<string, string> = {
    blue: 'bg-blue-50 text-blue-600',
    green: 'bg-emerald-50 text-emerald-600',
    amber: 'bg-amber-50 text-amber-600',
    indigo: 'bg-indigo-50 text-indigo-600'
  };

  return (
    <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
      <div className="flex items-center justify-between mb-4">
        <div className={`p-2.5 rounded-xl ${colors[color]}`}>
          <Icon size={22} />
        </div>
        <span className="text-[10px] font-bold text-slate-400 bg-slate-50 px-2 py-1 rounded-full uppercase">{trend}</span>
      </div>
      <div>
        <p className="text-slate-500 text-sm font-medium">{label}</p>
        <h4 className="text-2xl font-bold text-slate-800 mt-1">{value}</h4>
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { CreditCard, DollarSign, Calendar, FileText, CheckCircle, Clock, AlertTriangle, Printer } from 'lucide-react';
import { Student, FeeRecord, PaymentStatus, PaymentMethod } from '../types';
import { MONTHS, GRADES } from '../constants';

interface FeeManagementProps {
  students: Student[];
  fees: FeeRecord[];
  onAddFee: (fee: Omit<FeeRecord, 'id'>) => void;
  onUpdateFee: (id: string, updates: Partial<FeeRecord>) => void;
  onShowReceipt: (feeId: string) => void;
  searchTerm: string;
}

const FeeManagement: React.FC<FeeManagementProps> = ({ 
  students, fees, onAddFee, onUpdateFee, onShowReceipt, searchTerm 
}) => {
  const [showPayModal, setShowPayModal] = React.useState(false);
  const [selectedStudentId, setSelectedStudentId] = React.useState('');
  const [selectedMonth, setSelectedMonth] = React.useState(MONTHS[new Date().getMonth()]);
  const [amount, setAmount] = React.useState(2500);
  const [paidAmount, setPaidAmount] = React.useState(0);
  const [method, setMethod] = React.useState<PaymentMethod>(PaymentMethod.CASH);

  const filteredFees = fees.filter(fee => {
    const student = students.find(s => s.id === fee.studentId);
    if (!student) return false;
    const matchesSearch = student.name.toLowerCase().includes(searchTerm.toLowerCase()) || student.rollNumber.includes(searchTerm);
    return matchesSearch;
  });

  const getStudentName = (id: string) => students.find(s => s.id === id)?.name || 'Unknown';
  const getStudentGrade = (id: string) => students.find(s => s.id === id)?.grade || '-';

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    const status = paidAmount >= amount ? PaymentStatus.PAID : paidAmount > 0 ? PaymentStatus.PARTIAL : PaymentStatus.UNPAID;

    onAddFee({
      studentId: selectedStudentId,
      month: selectedMonth,
      year: 2023,
      totalAmount: amount,
      paidAmount: paidAmount,
      status,
      paymentDate: new Date().toISOString().split('T')[0],
      method,
      receiptNumber: `RCP-${Math.floor(1000 + Math.random() * 9000)}`
    });

    setShowPayModal(false);
    resetForm();
  };

  const resetForm = () => {
    setSelectedStudentId('');
    setPaidAmount(0);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Fee Management</h1>
          <p className="text-slate-500">Track collections and manage outstanding payments.</p>
        </div>
        <button 
          onClick={() => setShowPayModal(true)}
          className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-500/20"
        >
          <CreditCard size={18} />
          New Payment
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-200">
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Student</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Fee Period</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Amount</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredFees.map((fee) => (
                <tr key={fee.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-lg bg-indigo-50 flex items-center justify-center font-bold text-indigo-600">
                        {getStudentName(fee.studentId).charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-800">{getStudentName(fee.studentId)}</p>
                        <p className="text-xs text-slate-500">{getStudentGrade(fee.studentId)}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2 text-sm text-slate-600">
                      <Calendar size={14} />
                      {fee.month} {fee.year}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-sm font-bold text-slate-800">${fee.paidAmount} / ${fee.totalAmount}</span>
                      {fee.totalAmount - fee.paidAmount > 0 && (
                        <span className="text-[10px] text-red-500 font-bold uppercase tracking-wider">Due: ${fee.totalAmount - fee.paidAmount}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <StatusBadge status={fee.status} />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      {fee.status === PaymentStatus.PAID || fee.status === PaymentStatus.PARTIAL ? (
                        <button 
                          onClick={() => onShowReceipt(fee.id)}
                          className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-xs font-bold hover:bg-slate-200 transition-all"
                        >
                          <Printer size={14} />
                          Receipt
                        </button>
                      ) : (
                        <button 
                          onClick={() => {
                            setSelectedStudentId(fee.studentId);
                            setSelectedMonth(fee.month);
                            setAmount(fee.totalAmount);
