import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import StudentList from './components/StudentList';
import FeeManagement from './components/FeeManagement';
import Reports from './components/Reports';
import Receipt from './components/Receipt';
import { Student, FeeRecord, UserRole } from './types';
import { INITIAL_STUDENTS, INITIAL_FEES } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [role, setRole] = useState<UserRole>('Admin');
  const [searchTerm, setSearchTerm] = useState('');

  // Persistence using local storage
  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem('ef_students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });

  const [fees, setFees] = useState<FeeRecord[]>(() => {
    const saved = localStorage.getItem('ef_fees');
    return saved ? JSON.parse(saved) : INITIAL_FEES;
  });

  const [activeReceiptFeeId, setActiveReceiptFeeId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('ef_students', JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem('ef_fees', JSON.stringify(fees));
  }, [fees]);

  const handleAddStudent = (studentData: Omit<Student, 'id'>) => {
    const newStudent: Student = {
      ...studentData,
      id: `ST${(students.length + 1).toString().padStart(3, '0')}`
    };
    setStudents([...students, newStudent]);
  };

  const handleAddFee = (feeData: Omit<FeeRecord, 'id'>) => {
    const newFee: FeeRecord = {
      ...feeData,
      id: `F${(fees.length + 1).toString().padStart(3, '0')}`
    };
    setFees([...fees, newFee]);
    // Show receipt immediately if payment was made
    if (newFee.paidAmount > 0) {
      setActiveReceiptFeeId(newFee.id);
    }
  };

  const handleUpdateFee = (id: string, updates: Partial<FeeRecord>) => {
    setFees(fees.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  const currentReceiptData = React.useMemo(() => {
    if (!activeReceiptFeeId) return null;
    const fee = fees.find(f => f.id === activeReceiptFeeId);
    if (!fee) return null;
    const student = students.find(s => s.id === fee.studentId);
    if (!student) return null;
    return { fee, student };
  }, [activeReceiptFeeId, fees, students]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard students={students} fees={fees} />;
      case 'students':
        return <StudentList students={students} searchTerm={searchTerm} onAddStudent={handleAddStudent} />;
      case 'fees':
        return (
          <FeeManagement 
            students={students} 
            fees={fees} 
            searchTerm={searchTerm} 
            onAddFee={handleAddFee} 
            onUpdateFee={handleUpdateFee}
            onShowReceipt={(id) => setActiveReceiptFeeId(id)}
          />
        );
      case 'reports':
        return <Reports students={students} fees={fees} />;
      default:
        return <Dashboard students={students} fees={fees} />;
    }
  };

  return (
    <>
      <Layout 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        role={role} 
        setRole={setRole}
        searchTerm={searchTerm}
        setSearchTerm={setSearchTerm}
      >
        {renderContent()}
      </Layout>

      {currentReceiptData && (
        <Receipt 
          fee={currentReceiptData.fee} 
          student={currentReceiptData.student} 
          onClose={() => setActiveReceiptFeeId(null)} 
        />
      )}
    </>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { Student, FeeRecord } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getFinancialInsights(students: Student[], fees: FeeRecord[]) {
  const pendingFees = fees.filter(f => f.paidAmount < f.totalAmount);
  const totalPending = pendingFees.reduce((sum, f) => sum + (f.totalAmount - f.paidAmount), 0);

  const prompt = `
    Analyze this school fee data and provide 3-4 actionable financial insights for the administrator.
    Data Summary:
    - Total Students: ${students.length}
    - Total Pending Collections: Rs. ${totalPending}
    - Number of Pending Records: ${pendingFees.length}

    Pending Students Details:
    ${pendingFees.map(f => {
      const student = students.find(s => s.id === f.studentId);
      return `- ${student?.name} (${student?.grade}): Due Rs. ${f.totalAmount - f.paidAmount} for ${f.month}`;
    }).join('\n')}

    Format your response as a concise, professional list of recommendations. 
    Focus on collection strategies, communication with parents, and financial health in the context of a school in Pakistan.
    Keep it brief and encouraging.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Insights Error:", error);
    return "Could not generate insights at this time. Please check your collection reports manually.";
  }
}

