import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import StudentList from './components/StudentList';
import FeeManagement from './components/FeeManagement';
import Reports from './components/Reports';
import Receipt from './components/Receipt';
import { Student, FeeRecord, UserRole } from './types';
import { INITIAL_STUDENTS, INITIAL_FEES } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [role, setRole] = useState<UserRole>('Admin');
  const [searchTerm, setSearchTerm] = useState('');

  // Persistence using local storage
  const [students, setStudents] = useState<Student[]>(() => {
    const saved = localStorage.getItem('ef_students');
    return saved ? JSON.parse(saved) : INITIAL_STUDENTS;
  });

  const [fees, setFees] = useState<FeeRecord[]>(() => {
    const saved = localStorage.getItem('ef_fees');
    return saved ? JSON.parse(saved) : INITIAL_FEES;
  });

  const [activeReceiptFeeId, setActiveReceiptFeeId] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('ef_students', JSON.stringify(students));
  }, [students]);

  useEffect(() => {
    localStorage.setItem('ef_fees', JSON.stringify(fees));
  }, [fees]);

  const handleAddStudent = (studentData: Omit<Student, 'id'>) => {
    const newStudent: Student = {
      ...studentData,
      id: `ST${Date.now()}` // More reliable unique ID
    };
    setStudents(prev => [...prev, newStudent]);
  };

  const handleUpdateStudent = (id: string, updates: Omit<Student, 'id'>) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...updates, id } : s));
  };

  const handleDeleteStudent = (id: string) => {
    if (window.confirm('Are you sure you want to delete this student and all their fee records? This action cannot be undone.')) {
      setStudents(prev => prev.filter(s => s.id !== id));
      setFees(prev => prev.filter(f => f.studentId !== id));
    }
  };

  const handleAddFee = (feeData: Omit<FeeRecord, 'id'>) => {
    const newFee: FeeRecord = {
      ...feeData,
      id: `F${Date.now()}`
    };
    setFees(prev => [...prev, newFee]);
    // Show receipt immediately if payment was made
    if (newFee.paidAmount > 0) {
      setActiveReceiptFeeId(newFee.id);
    }
  };

  const handleUpdateFee = (id: string, updates: Partial<FeeRecord>) => {
    setFees(prev => prev.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  const currentReceiptData = React.useMemo(() => {
    if (!activeReceiptFeeId) return null;
    const fee = fees.find(f => f.id === activeReceiptFeeId);
    if (!fee) return null;
    const student = students.find(s => s.id === fee.studentId);
    if (!student) return null;
    return { fee, student };
  }, [activeReceiptFeeId, fees, students]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard students={students} fees={fees} />;
      case 'students':
        return (
          <StudentList 
            students={students} 
            searchTerm={searchTerm} 
            onAddStudent={handleAddStudent} 
            onUpdateStudent={handleUpdateStudent}
            onDeleteStudent={handleDeleteStudent}
          />
        );
      case 'fees':
        return (
          <FeeManagement 
            students={students} 
            fees={fees} 
            searchTerm={searchTerm} 
            onAddFee={handleAddFee} 
            onUpdateFee={handleUpdateFee}
            onShowReceipt={(id) => setActiveReceiptFeeId(id)}
          />
        );
      case 'reports':
        return <Reports students={students} fees={fees} />;
      default:
        return <Dashboard students={students} fees={fees} />;
    }
  };

  return (
    <>
      <Layout 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        role={role} 
        setRole={setRole}
        searchTerm={searchTerm}
        setSearchTerm={setSearchTerm}
      >
        {renderContent()}
      </Layout>

      {currentReceiptData && (
        <Receipt 
          fee={currentReceiptData.fee} 
          student={currentReceiptData.student} 
          onClose={() => setActiveReceiptFeeId(null)} 
        />
      )}
    </>
  );
};

