    if (!isInit && !saved) {
      localStorage.setItem(STORAGE_KEY_INIT, 'true');
      localStorage.setItem(STORAGE_KEY_STUDENTS, JSON.stringify(INITIAL_STUDENTS));
      return INITIAL_STUDENTS;
