}

const Reports: React.FC<ReportsProps> = ({ students, fees }) => {
  const [filterMonth, setFilterMonth] = React.useState('All');
  const [filterGrade, setFilterGrade] = React.useState('All');
  const [reportSearch, setReportSearch] = React.useState('');

  // Filter logic
  const filteredFees = React.useMemo(() => {
    return fees.filter(fee => {
      const student = students.find(s => s.id === fee.studentId);
      const monthMatch = filterMonth === 'All' || fee.month === filterMonth;
      const gradeMatch = filterGrade === 'All' || student?.grade === filterGrade;
      const searchMatch = reportSearch === '' || 
        student?.name.toLowerCase().includes(reportSearch.toLowerCase()) ||
        student?.rollNumber.includes(reportSearch);

      return monthMatch && gradeMatch && searchMatch;
    });
  }, [fees, students, filterMonth, filterGrade, reportSearch]);

  const pendingFees = filteredFees.filter(f => f.status !== PaymentStatus.PAID);
  const totalPending = pendingFees.reduce((sum, f) => sum + (f.totalAmount - f.paidAmount), 0);
  const totalCollected = filteredFees.reduce((sum, f) => sum + f.paidAmount, 0);

  const handleExportCSV = () => {
    const headers = ['Student Name', 'Roll Number', 'Grade', 'Month', 'Year', 'Total Amount (Rs.)', 'Paid Amount (Rs.)', 'Balance (Rs.)', 'Status'];
    const rows = filteredFees.map(fee => {
      const student = students.find(s => s.id === fee.studentId);
      return [
        `"${student?.name || 'Unknown'}"`,
        `"${student?.rollNumber || ''}"`,
        `"${student?.grade || ''}"`,
        fee.month,
        fee.year,
        fee.totalAmount,
        fee.paidAmount,
        fee.totalAmount - fee.paidAmount,
        fee.status
      ];
    });

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    const fileName = `APS_Report_${filterMonth}_${filterGrade}_${new Date().toISOString().split('T')[0]}.csv`;
    link.setAttribute("download", fileName);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-6">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Financial Reports</h1>
          <p className="text-slate-500">Comprehensive view of school collections and arrears.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          {/* Month Filter */}
          <div className="relative min-w-[140px]">
            <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <select 
              value={filterMonth}
              onChange={(e) => setFilterMonth(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-semibold text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 appearance-none cursor-pointer"
            >
              <option value="All">All Months</option>
              {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>

          {/* Grade Filter */}
          <div className="relative min-w-[140px]">
            <GraduationCap className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <select 
              value={filterGrade}
              onChange={(e) => setFilterGrade(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-semibold text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 appearance-none cursor-pointer"
            >
              <option value="All">All Grades</option>
              {GRADES.map(g => <option key={g} value={g}>{g}</option>)}
            </select>
          </div>

          <button 
            onClick={handleExportCSV}
            className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-slate-800 transition-all shadow-lg shadow-slate-900/10"
          >
            <FileDown size={18} />
            Export CSV
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-gradient-to-br from-indigo-600 to-indigo-800 p-6 rounded-3xl text-white shadow-xl shadow-indigo-500/20 transition-transform hover:scale-[1.02]">
          <div className="flex items-center gap-3 mb-4 opacity-80">
            <Banknote size={20} />
            <span className="text-xs font-bold uppercase tracking-widest">Selected Collection</span>
          </div>
          <h3 className="text-4xl font-black mb-2">Rs. {totalCollected.toLocaleString()}</h3>
          <p className="text-indigo-100 text-xs font-medium">For {filterMonth} / {filterGrade}</p>
        </div>

        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col justify-between transition-transform hover:scale-[1.02]">
          <div>
            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Outstanding (Selected)</span>
            <h3 className="text-3xl font-black text-slate-800 mt-2">Rs. {totalPending.toLocaleString()}</h3>
          </div>
          <div className="mt-4 flex items-center gap-2">
            <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden">
              <div 
                className="h-full bg-amber-500 transition-all duration-500" 
                style={{width: `${(totalPending / (totalCollected + totalPending || 1)) * 100}%`}}
              ></div>
            </div>
            <span className="text-[10px] font-bold text-slate-500 uppercase">Arrears Ratio</span>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col justify-between transition-transform hover:scale-[1.02]">
          <div>
            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Active Defaulters</span>
            <h3 className="text-3xl font-black text-slate-800 mt-2">{pendingFees.length} Students</h3>
          </div>
          <div className="mt-4 flex items-center text-emerald-600 font-bold text-sm">
            <TrendingUp size={16} className="mr-2" />
            <span>Reflecting current filters</span>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-6 py-5 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between bg-slate-50/50 gap-4">
          <h3 className="font-bold text-slate-800">Defaulter List (Filtered View)</h3>
          <div className="relative">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by student or roll..." 
              value={reportSearch}
              onChange={(e) => setReportSearch(e.target.value)}
              className="pl-9 pr-4 py-2 text-xs rounded-xl border bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500/10 focus:border-indigo-300 w-full sm:w-64" 
            />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="border-b border-slate-100">
                <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase">Student Name</th>
                <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase">Grade</th>
                <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase">Period</th>
                <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase text-right">Amount Due</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {pendingFees.map((fee) => {
                const student = students.find(s => s.id === fee.studentId);
                return (
                  <tr key={fee.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <p className="text-sm font-bold text-slate-800">{student?.name}</p>
