import React from 'react';
import { CreditCard, Banknote, Calendar, FileText, CheckCircle, Clock, AlertTriangle, Printer, AlertCircle } from 'lucide-react';
import { Student, FeeRecord, PaymentStatus, PaymentMethod } from '../types';
import { MONTHS, GRADES } from '../constants';

interface FeeManagementProps {
  students: Student[];
  fees: FeeRecord[];
  onAddFee: (fee: Omit<FeeRecord, 'id'>) => void;
  onUpdateFee: (id: string, updates: Partial<FeeRecord>) => void;
  onShowReceipt: (feeId: string) => void;
  searchTerm: string;
}

const FeeManagement: React.FC<FeeManagementProps> = ({ 
  students, fees, onAddFee, onUpdateFee, onShowReceipt, searchTerm 
}) => {
  const [showPayModal, setShowPayModal] = React.useState(false);
  const [selectedStudentId, setSelectedStudentId] = React.useState('');
  const [selectedMonth, setSelectedMonth] = React.useState(MONTHS[new Date().getMonth()]);
  const [amount, setAmount] = React.useState(2500);
  const [paidAmount, setPaidAmount] = React.useState(0);
  const [method, setMethod] = React.useState<PaymentMethod>(PaymentMethod.CASH);
  const [error, setError] = React.useState<string | null>(null);

  const filteredFees = fees.filter(fee => {
    const student = students.find(s => s.id === fee.studentId);
    if (!student) return false;
    const matchesSearch = student.name.toLowerCase().includes(searchTerm.toLowerCase()) || student.rollNumber.includes(searchTerm);
    return matchesSearch;
  });

  const getStudentName = (id: string) => students.find(s => s.id === id)?.name || 'Unknown';
  const getStudentGrade = (id: string) => students.find(s => s.id === id)?.grade || '-';

  const handlePayment = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Check for duplicate entry (same student, same month)
    const isDuplicate = fees.some(
      (f) => f.studentId === selectedStudentId && f.month === selectedMonth
    );

    if (isDuplicate) {
      setError("This record already exists.");
      return;
    }

    const status = paidAmount >= amount ? PaymentStatus.PAID : paidAmount > 0 ? PaymentStatus.PARTIAL : PaymentStatus.UNPAID;

    onAddFee({
      studentId: selectedStudentId,
      month: selectedMonth,
      year: 2023,
      totalAmount: amount,
      paidAmount: paidAmount,
      status,
      paymentDate: new Date().toISOString().split('T')[0],
      method,
      receiptNumber: `RCP-${Math.floor(1000 + Math.random() * 9000)}`
    });

    setShowPayModal(false);
    resetForm();
  };

  const resetForm = () => {
    setSelectedStudentId('');
    setPaidAmount(0);
    setError(null);
  };

  const handleCloseModal = () => {
    setShowPayModal(false);
    resetForm();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Fee Management</h1>
          <p className="text-slate-500">Track collections and manage outstanding payments.</p>
        </div>
        <button 
          onClick={() => setShowPayModal(true)}
          className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl font-medium flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-500/20"
        >
          <CreditCard size={18} />
          New Payment
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-200">
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Student</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Fee Period</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Amount (Rs.)</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredFees.map((fee) => (
                <tr key={fee.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-lg bg-indigo-50 flex items-center justify-center font-bold text-indigo-600">
                        {getStudentName(fee.studentId).charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-800">{getStudentName(fee.studentId)}</p>
                        <p className="text-xs text-slate-500">{getStudentGrade(fee.studentId)}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2 text-sm text-slate-600">
                      <Calendar size={14} />
                      {fee.month} {fee.year}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-sm font-bold text-slate-800">Rs. {fee.paidAmount} / Rs. {fee.totalAmount}</span>
                      {fee.totalAmount - fee.paidAmount > 0 && (
                        <span className="text-[10px] text-red-500 font-bold uppercase tracking-wider">Due: Rs. {fee.totalAmount - fee.paidAmount}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <StatusBadge status={fee.status} />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      {fee.status === PaymentStatus.PAID || fee.status === PaymentStatus.PARTIAL ? (
                        <button 
                          onClick={() => onShowReceipt(fee.id)}
                          className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 text-slate-600 rounded-lg text-xs font-bold hover:bg-slate-200 transition-all"
                        >
                          <Printer size={14} />
                          Receipt
                        </button>
                      ) : (
                        <button 
                          onClick={() => {
                            setSelectedStudentId(fee.studentId);
                            setSelectedMonth(fee.month);
                            setAmount(fee.totalAmount);
                            setShowPayModal(true);
                          }}
                          className="px-3 py-1.5 bg-blue-600 text-white rounded-lg text-xs font-bold hover:bg-blue-700 transition-all"
                        >
                          Pay Now
                        </button>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredFees.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-slate-400 italic">
                    No fee records found. Start by recording a payment.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Payment Modal */}
      {showPayModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-3xl w-full max-w-md shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-200">
            <div className="px-8 py-6 border-b border-slate-100 bg-indigo-50/50">
              <h3 className="text-xl font-bold text-slate-800">Process Payment (PKR)</h3>
              <p className="text-sm text-slate-500">Enter payment details to generate a receipt.</p>
            </div>
            <form onSubmit={handlePayment} className="p-8 space-y-5">
              {error && (
                <div className="bg-red-50 border border-red-200 text-red-600 px-4 py-3 rounded-xl text-sm font-bold flex items-center gap-2 animate-in fade-in zoom-in duration-200">
                  <AlertCircle size={18} />
                  {error}
                </div>
              )}

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-600">Select Student</label>
                <select 
                  required
                  value={selectedStudentId}
                  onChange={e => {
                    setSelectedStudentId(e.target.value);
                    if (error) setError(null);
                  }}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all"
                >
                  <option value="">Choose a student...</option>
                  {students.map(s => <option key={s.id} value={s.id}>{s.name} ({s.rollNumber})</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-600">Fee Month</label>
                  <select 
                    value={selectedMonth}
                    onChange={e => {
                      setSelectedMonth(e.target.value);
                      if (error) setError(null);
                    }}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none"
                  >
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-600">Total Fee (Rs.)</label>
                  <input 
                    type="number"
                    value={amount}
                    onChange={e => setAmount(Number(e.target.value))}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-600">Amount Being Paid (Rs.)</label>
                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold text-xs">Rs.</div>
                  <input 
                    required
                    type="number"
                    value={paidAmount}
                    onChange={e => setPaidAmount(Number(e.target.value))}
                    className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 outline-none"
                    placeholder="Enter amount"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-600">Payment Method</label>
                <div className="grid grid-cols-3 gap-2">
                  {Object.values(PaymentMethod).map(m => (
                    <button
                      key={m}
                      type="button"
                      onClick={() => setMethod(m)}
                      className={`py-2 text-xs font-bold rounded-lg border transition-all ${
                        method === m 
                          ? 'bg-indigo-600 text-white border-indigo-600' 
                          : 'bg-white text-slate-500 border-slate-200 hover:border-indigo-200'
                      }`}
                    >
                      {m}
                    </button>
                  ))}
                </div>
              </div>

              <div className="pt-4 flex items-center gap-3">
                <button 
                  type="button"
                  onClick={handleCloseModal}
                  className="flex-1 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-50 transition-all border border-transparent"
                >
                  Discard
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-3 rounded-xl bg-indigo-600 text-white font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-500/20"
                >
                  Record Payment
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const StatusBadge: React.FC<{status: PaymentStatus}> = ({ status }) => {
  switch (status) {
    case PaymentStatus.PAID:
      return (
        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-emerald-50 text-emerald-700 text-[10px] font-bold uppercase tracking-wider">
          <CheckCircle size={12} />
          Paid
        </span>
      );
    case PaymentStatus.PARTIAL:
      return (
        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-amber-50 text-amber-700 text-[10px] font-bold uppercase tracking-wider">
          <Clock size={12} />
          Partial
        </span>
      );
    case PaymentStatus.UNPAID:
      return (
        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-red-50 text-red-700 text-[10px] font-bold uppercase tracking-wider">
          <AlertTriangle size={12} />
          Unpaid
        </span>
      );
  }
};

