import React from 'react';
import { FileDown, Calendar, Search, ArrowRight, TrendingUp, Banknote, GraduationCap, Info, ChevronRight, CheckCircle2, Clock, AlertCircle } from 'lucide-react';
import { Student, FeeRecord, PaymentStatus } from '../types';
import { MONTHS, GRADES } from '../constants';

interface ReportsProps {
  students: Student[];
  fees: FeeRecord[];
}

interface StudentLedger {
  student: Student;
  paidMonths: string[];
  pendingMonths: { month: string; amount: number; remarks?: string }[];
  totalDue: number;
  totalPaid: number;
  balance: number;
}

const Reports: React.FC<ReportsProps> = ({ students, fees }) => {
  const [filterGrade, setFilterGrade] = React.useState('All');
  const [reportSearch, setReportSearch] = React.useState('');

  // Transform flat fees into a student-wise ledger
  const studentLedgers: StudentLedger[] = React.useMemo(() => {
    return students
      .filter(s => {
        const gradeMatch = filterGrade === 'All' || s.grade === filterGrade;
        const searchMatch = reportSearch === '' || 
          s.name.toLowerCase().includes(reportSearch.toLowerCase()) ||
          s.rollNumber.includes(reportSearch);
        return gradeMatch && searchMatch;
      })
      .map(student => {
        const studentFees = fees.filter(f => f.studentId === student.id);
        const paidMonths = studentFees
          .filter(f => f.status === PaymentStatus.PAID)
          .map(f => f.month);

        const pendingMonths = studentFees
          .filter(f => f.status !== PaymentStatus.PAID)
          .map(f => ({
            month: f.month,
            amount: f.totalAmount - f.paidAmount,
            remarks: f.remarks
          }));

        const totalDue = studentFees.reduce((sum, f) => sum + f.totalAmount, 0);
        const totalPaid = studentFees.reduce((sum, f) => sum + f.paidAmount, 0);
        const balance = totalDue - totalPaid;

        return {
          student,
          paidMonths,
          pendingMonths,
          totalDue,
          totalPaid,
          balance
        };
      })
      .sort((a, b) => b.balance - a.balance); // Show highest debtors first
  }, [students, fees, filterGrade, reportSearch]);

  const totalOutstanding = studentLedgers.reduce((sum, l) => sum + l.balance, 0);
  const totalCollected = studentLedgers.reduce((sum, l) => sum + l.totalPaid, 0);

  const handleExportCSV = () => {
    const headers = ['Roll No', 'Name', 'Grade', 'Paid Months', 'Pending Months', 'Total Due', 'Total Paid', 'Remaining Balance'];
    const rows = studentLedgers.map(l => [
      `"${l.student.rollNumber}"`,
      `"${l.student.name}"`,
      `"${l.student.grade}"`,
      `"${l.paidMonths.join(', ')}"`,
      `"${l.pendingMonths.map(p => `${p.month} (Rs. ${p.amount})`).join(', ')}"`,
      l.totalDue,
      l.totalPaid,
      l.balance
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `APS_Ledger_Report_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-6">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Student Financial Ledger</h1>
          <p className="text-slate-500">Student-wise monthly breakdown and remaining balances.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          <div className="relative min-w-[140px]">
            <GraduationCap className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <select 
              value={filterGrade}
              onChange={(e) => setFilterGrade(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-semibold text-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 appearance-none cursor-pointer shadow-sm"
            >
              <option value="All">All Grades</option>
              {GRADES.map(g => <option key={g} value={g}>{g}</option>)}
            </select>
          </div>

          <button 
            onClick={handleExportCSV}
            className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-xl font-medium hover:bg-slate-800 transition-all shadow-lg shadow-slate-900/10"
          >
            <FileDown size={18} />
            Download Ledger
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between">
          <div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Total Outstanding (Filtered)</span>
            <h3 className="text-3xl font-black text-red-600">Rs. {totalOutstanding.toLocaleString()}</h3>
          </div>
          <div className="w-12 h-12 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center">
            <AlertCircle size={24} />
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between">
          <div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Total Collections (Filtered)</span>
            <h3 className="text-3xl font-black text-emerald-600">Rs. {totalCollected.toLocaleString()}</h3>
          </div>
          <div className="w-12 h-12 bg-emerald-50 text-emerald-500 rounded-2xl flex items-center justify-center">
            <Banknote size={24} />
          </div>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="px-6 py-5 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between bg-slate-50/50 gap-4">
          <h3 className="font-bold text-slate-800">Detailed Student Ledger</h3>
          <div className="relative">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search student or roll number..." 
              value={reportSearch}
              onChange={(e) => setReportSearch(e.target.value)}
              className="pl-9 pr-4 py-2 text-xs rounded-xl border bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500/10 focus:border-indigo-300 w-full sm:w-64 shadow-sm" 
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-white border-b border-slate-100">
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Student & Grade</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Payment History (Months)</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pending & Reasons</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Balance As of Today</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {studentLedgers.map((ledger) => (
                <tr key={ledger.student.id} className="hover:bg-slate-50/50 transition-colors align-top">
                  <td className="px-6 py-5 min-w-[200px]">
                    <p className="text-sm font-black text-slate-800 mb-1">{ledger.student.name}</p>
                    <div className="flex items-center gap-2">
                      <span className="text-[10px] font-bold px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded">Roll: {ledger.student.rollNumber}</span>
                      <span className="text-[10px] font-bold px-1.5 py-0.5 bg-indigo-50 text-indigo-600 rounded">{ledger.student.grade}</span>
                    </div>
                  </td>

                  <td className="px-6 py-5">
                    <div className="flex flex-wrap gap-1.5 max-w-xs">
                      {ledger.paidMonths.length > 0 ? (
                        ledger.paidMonths.map(m => (
                          <span key={m} className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-emerald-50 text-emerald-600 text-[10px] font-bold">
                            <CheckCircle2 size={10} />
                            {m}
                          </span>
                        ))
                      ) : (
                        <span className="text-xs text-slate-400 italic">No payments yet</span>
                      )}
                    </div>
                  </td>

                  <td className="px-6 py-5">
                    <div className="space-y-2 max-w-sm">
                      {ledger.pendingMonths.length > 0 ? (
                        ledger.pendingMonths.map(p => (
                          <div key={p.month} className="bg-amber-50/50 rounded-lg p-2 border border-amber-100">
                            <div className="flex items-center justify-between mb-1">
                              <span className="text-[10px] font-black text-amber-700 uppercase tracking-tight">{p.month}</span>
                              <span className="text-[10px] font-black text-red-500">Rs. {p.amount.toLocaleString()}</span>
                            </div>
                            {p.remarks && (
                              <p className="text-[9px] text-slate-500 font-medium leading-tight">
                                <span className="text-amber-600 font-bold">Reason:</span> {p.remarks}
                              </p>
                            )}
                          </div>
                        ))
                      ) : (
                        <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-indigo-50 text-indigo-600 text-[10px] font-bold">
                          All Clear
                        </span>
                      )}
                    </div>
                  </td>

                  <td className="px-6 py-5 text-right">
                    <div className="flex flex-col items-end">
                      <span className={`text-lg font-black ${ledger.balance > 0 ? 'text-red-500' : 'text-slate-800'}`}>
                        Rs. {ledger.balance.toLocaleString()}
                      </span>
                      <div className="flex items-center gap-1 text-[9px] font-bold text-slate-400 mt-1 uppercase tracking-tighter">
                        <TrendingUp size={10} />
                        Total Paid: Rs. {ledger.totalPaid.toLocaleString()}
                      </div>
                    </div>
                  </td>
                </tr>
              ))}
              {studentLedgers.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-6 py-20 text-center">
                    <div className="flex flex-col items-center gap-2 text-slate-400">
                      <Search size={40} className="opacity-20 mb-2" />
                      <p className="font-bold">No students found</p>
                      <p className="text-xs">Adjust your search or filter to see results.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="flex items-center gap-2 text-[10px] text-slate-400 font-medium bg-slate-50 p-4 rounded-xl border border-slate-100">
        <Info size={14} className="text-slate-500" />
        <span>This report generates a consolidated view. To edit individual month records, go to the <strong>Fee Management</strong> section. Remaining balance is calculated by subtracting total paid from total due across all recorded months.</span>
      </div>
    </div>
  );
};

