import React from 'react';
import { 
  CreditCard, 
  Banknote, 
  Calendar, 
  CheckCircle, 
  Clock, 
  AlertTriangle, 
  Printer, 
  AlertCircle, 
  Search, 
  ArrowRight, 
  ChevronRight,
  Wallet,
  History,
  Info
} from 'lucide-react';
import { Student, FeeRecord, PaymentStatus, PaymentMethod } from '../types';
import { MONTHS, GRADE_FEES } from '../constants';

interface FeeManagementProps {
  students: Student[];
  fees: FeeRecord[];
  onAddFee: (fee: Omit<FeeRecord, 'id'>) => void;
  onUpdateFee: (id: string, updates: Partial<FeeRecord>) => void;
  onShowReceipt: (feeId: string) => void;
  searchTerm: string;
}

const FeeManagement: React.FC<FeeManagementProps> = ({ 
  students, fees, onAddFee, onUpdateFee, onShowReceipt, searchTerm 
}) => {
  const [selectedStudent, setSelectedStudent] = React.useState<Student | null>(null);
  const [showPayModal, setShowPayModal] = React.useState(false);
  const [payTargetMonth, setPayTargetMonth] = React.useState<string>(MONTHS[new Date().getMonth()]);
  const [payAmount, setPayAmount] = React.useState<number>(0);
  const [payMethod, setPayMethod] = React.useState<PaymentMethod>(PaymentMethod.CASH);
  const [payRemarks, setPayRemarks] = React.useState('');
  const [error, setError] = React.useState<string | null>(null);

  // Filter students based on search
  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.rollNumber.includes(searchTerm)
  );

  const getStudentStats = (studentId: string) => {
    const studentFees = fees.filter(f => f.studentId === studentId);
    const totalDue = studentFees.reduce((sum, f) => sum + f.totalAmount, 0);
    const totalPaid = studentFees.reduce((sum, f) => sum + f.paidAmount, 0);
    const balance = totalDue - totalPaid;
    return { totalDue, totalPaid, balance, count: studentFees.length };
  };

  const handleOpenPayModal = (student: Student, month?: string, remaining?: number) => {
    const standardFee = GRADE_FEES[student.grade] || 2500;
    setSelectedStudent(student);
    setPayTargetMonth(month || MONTHS[new Date().getMonth()]);
    setPayAmount(remaining !== undefined ? remaining : standardFee);
    setPayRemarks('');
    setError(null);
    setShowPayModal(true);
  };

  const handleProcessPayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) return;

    // Check if a record already exists for this month
    const existingFee = fees.find(f => f.studentId === selectedStudent.id && f.month === payTargetMonth);

    if (existingFee) {
      if (existingFee.status === PaymentStatus.PAID) {
        setError("This month is already fully paid.");
        return;
      }

      // Update existing record (clear balance)
      const newPaidAmount = existingFee.paidAmount + payAmount;
      const newStatus = newPaidAmount >= existingFee.totalAmount ? PaymentStatus.PAID : PaymentStatus.PARTIAL;

      onUpdateFee(existingFee.id, {
        paidAmount: newPaidAmount,
        status: newStatus,
        remarks: payRemarks || existingFee.remarks,
        paymentDate: new Date().toISOString().split('T')[0]
      });
    } else {
      // Create new record based on Grade Fee structure
      const standardFee = GRADE_FEES[selectedStudent.grade] || 2500;
      const status = payAmount >= standardFee ? PaymentStatus.PAID : payAmount > 0 ? PaymentStatus.PARTIAL : PaymentStatus.UNPAID;

      onAddFee({
        studentId: selectedStudent.id,
        month: payTargetMonth,
        year: 2023,
        totalAmount: standardFee,
        paidAmount: payAmount,
        status,
        paymentDate: new Date().toISOString().split('T')[0],
        method: payMethod,
        remarks: payRemarks,
        receiptNumber: `RCP-${Math.floor(1000 + Math.random() * 9000)}`
      });
    }

    setShowPayModal(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Fee Ledger Management</h1>
          <p className="text-slate-500">View and manage student financial records individually.</p>
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 border-b border-slate-200">
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Student Information</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Fee Status</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Outstanding Balance</th>
                <th className="px-6 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredStudents.map((student) => {
                const stats = getStudentStats(student.id);
                return (
                  <tr key={student.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-5">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-2xl bg-indigo-600 flex items-center justify-center font-bold text-white shadow-lg shadow-indigo-200">
                          {student.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-black text-slate-800 text-sm leading-tight">{student.name}</p>
                          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Roll: {student.rollNumber} • {student.grade}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="flex flex-col items-center">
                        <div className="flex -space-x-1">
                          {fees.filter(f => f.studentId === student.id).slice(0, 5).map((f, i) => (
                            <div 
                              key={f.id} 
                              className={`w-5 h-5 rounded-full border-2 border-white flex items-center justify-center text-[8px] font-bold text-white shadow-sm ${
                                f.status === PaymentStatus.PAID ? 'bg-emerald-500' : f.status === PaymentStatus.PARTIAL ? 'bg-amber-500' : 'bg-red-500'
                              }`}
                              title={`${f.month}: ${f.status}`}
                            >
                              {f.month.charAt(0)}
                            </div>
                          ))}
                          {stats.count > 5 && (
                            <div className="w-5 h-5 rounded-full border-2 border-white bg-slate-200 text-[8px] font-bold text-slate-500 flex items-center justify-center">
                              +{stats.count - 5}
                            </div>
                          )}
                        </div>
                        <span className="text-[9px] font-bold text-slate-400 mt-1 uppercase">{stats.count} Month(s) Recorded</span>
                      </div>
                    </td>
                    <td className="px-6 py-5 text-right">
                      <div className="flex flex-col items-end">
                        <span className={`text-base font-black ${stats.balance > 0 ? 'text-red-500' : 'text-emerald-600'}`}>
                          Rs. {stats.balance.toLocaleString()}
                        </span>
                        <span className="text-[10px] text-slate-400 font-bold uppercase">Net Remaining</span>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <div className="flex items-center justify-center gap-2">
                        <button 
                          onClick={() => handleOpenPayModal(student)}
                          className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-black hover:bg-indigo-700 transition-all shadow-md shadow-indigo-200 flex items-center gap-2"
                        >
                          <Wallet size={14} />
                          Collect Fee
                        </button>
                        <button 
                          onClick={() => setSelectedStudent(student)}
                          className="p-2 bg-slate-100 text-slate-500 rounded-xl hover:bg-slate-200 transition-all"
                          title="View Full Ledger"
                        >
                          <History size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {selectedStudent && !showPayModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-end bg-slate-900/30 backdrop-blur-sm p-4">
          <div className="bg-white h-full w-full max-w-2xl rounded-[2rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right duration-300">
            <div className="p-8 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 rounded-2xl bg-indigo-600 flex items-center justify-center text-white text-xl font-black">
                  {selectedStudent.name.charAt(0)}
                </div>
                <div>
                  <h2 className="text-xl font-black text-slate-800">{selectedStudent.name}</h2>
                  <p className="text-sm text-slate-500 font-medium">{selectedStudent.grade} • Roll: {selectedStudent.rollNumber}</p>
                </div>
              </div>
              <button 
                onClick={() => setSelectedStudent(null)}
                className="p-2 hover:bg-slate-200 rounded-xl transition-all"
              >
                <ArrowRight size={24} className="text-slate-400" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-6">
              <div className="grid grid-cols-3 gap-4">
                <div className="bg-indigo-50/50 p-4 rounded-2xl border border-indigo-100">
                  <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest block mb-1">Total Due</span>
                  <p className="text-lg font-black text-indigo-700">Rs. {getStudentStats(selectedStudent.id).totalDue.toLocaleString()}</p>
                </div>
                <div className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100">
                  <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest block mb-1">Received</span>
                  <p className="text-lg font-black text-emerald-700">Rs. {getStudentStats(selectedStudent.id).totalPaid.toLocaleString()}</p>
                </div>
                <div className="bg-red-50/50 p-4 rounded-2xl border border-red-100">
                  <span className="text-[10px] font-black text-red-400 uppercase tracking-widest block mb-1">Arrears</span>
                  <p className="text-lg font-black text-red-700">Rs. {getStudentStats(selectedStudent.id).balance.toLocaleString()}</p>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <h3 className="font-black text-slate-800 flex items-center gap-2">
                    <Calendar size={18} className="text-slate-400" />
                    Monthly History
                  </h3>
                  <div className="text-[10px] font-bold text-slate-400 uppercase bg-slate-100 px-2 py-1 rounded">
                    Grade Fee: Rs. {GRADE_FEES[selectedStudent.grade]?.toLocaleString()}
                  </div>
                </div>
                <div className="space-y-2">
                  {MONTHS.map(month => {
                    const fee = fees.find(f => f.studentId === selectedStudent.id && f.month === month);
                    const standardFee = GRADE_FEES[selectedStudent.grade] || 2500;
                    return (
                      <div key={month} className="flex items-center justify-between p-4 rounded-2xl border border-slate-100 hover:bg-slate-50 transition-all">
                        <div className="flex items-center gap-4">
                          <div className={`w-2 h-2 rounded-full ${fee ? (fee.status === PaymentStatus.PAID ? 'bg-emerald-500' : 'bg-amber-500') : 'bg-slate-200'}`} />
                          <div>
                            <p className="font-bold text-slate-800 text-sm">{month}</p>
                            {fee && fee.remarks && <p className="text-[10px] text-slate-400">{fee.remarks}</p>}
                          </div>
                        </div>
                        <div className="flex items-center gap-4">
                          {fee ? (
                            <div className="text-right mr-4">
                              <p className="text-xs font-black text-slate-800">Rs. {fee.paidAmount.toLocaleString()}</p>
                              {fee.totalAmount - fee.paidAmount > 0 && (
                                <p className="text-[10px] font-bold text-red-500">Balance: Rs. {(fee.totalAmount - fee.paidAmount).toLocaleString()}</p>
                              )}
                            </div>
                          ) : (
                            <span className="text-xs text-slate-300 italic mr-4">No record</span>
                          )}

                          {(!fee || fee.status !== PaymentStatus.PAID) ? (
                            <button 
                              onClick={() => handleOpenPayModal(selectedStudent, month, fee ? (fee.totalAmount - fee.paidAmount) : standardFee)}
                              className="px-3 py-1.5 bg-indigo-600 text-white rounded-lg text-[10px] font-black uppercase tracking-tighter hover:bg-indigo-700"
                            >
                              {fee ? 'Clear Balance' : 'Collect'}
                            </button>
                          ) : (
                            <button 
                              onClick={() => onShowReceipt(fee.id)}
                              className="p-1.5 bg-slate-100 text-slate-500 rounded-lg hover:bg-slate-200"
                            >
                              <Printer size={14} />
                            </button>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {showPayModal && selectedStudent && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-md shadow-2xl overflow-hidden border border-slate-100">
            <div className="p-8 border-b border-slate-100 bg-indigo-50/30">
              <h3 className="text-xl font-black text-slate-800">Collect Payment</h3>
              <p className="text-xs text-slate-500 font-bold uppercase tracking-widest mt-1">
                {selectedStudent.name} • {payTargetMonth}
              </p>
            </div>

            <form onSubmit={handleProcessPayment} className="p-8 space-y-5">
              {error && (
                <div className="bg-red-50 border border-red-200 text-red-600 p-3 rounded-xl text-xs font-bold flex items-center gap-2">
                  <AlertCircle size={16} />
                  {error}
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Month</label>
                  <select 
                    value={payTargetMonth}
                    onChange={e => setPayTargetMonth(e.target.value)}
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 text-sm font-bold bg-slate-50 focus:ring-2 focus:ring-indigo-500/20 outline-none"
                  >
                    {MONTHS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Method</label>
                  <select 
                    value={payMethod}
                    onChange={e => setPayMethod(e.target.value as PaymentMethod)}
                    className="w-full px-4 py-3 rounded-2xl border border-slate-200 text-sm font-bold bg-slate-50 focus:ring-2 focus:ring-indigo-500/20 outline-none"
                  >
                    {Object.values(PaymentMethod).map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Amount to Collect (Rs.)</label>
                <div className="relative">
                  <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-black text-xs">Rs.</div>
                  <input 
                    required
                    type="number"
                    value={payAmount}
                    onChange={e => setPayAmount(Number(e.target.value))}
                    className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-emerald-100 bg-emerald-50/20 text-emerald-700 font-black text-lg focus:border-emerald-500 outline-none transition-all"
                  />
                </div>
                <p className="text-[9px] text-slate-400 font-bold uppercase text-right">Standard Grade Fee: Rs. {GRADE_FEES[selectedStudent.grade]?.toLocaleString()}</p>
              </div>

              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Remarks</label>
                <textarea 
                  value={payRemarks}
                  onChange={e => setPayRemarks(e.target.value)}
                  className="w-full px-4 py-3 rounded-2xl border border-slate-200 text-sm focus:ring-2 focus:ring-indigo-500/20 outline-none h-20 resize-none"
                  placeholder="e.g. Received partial cash, father will pay rest on Friday."
                />
              </div>

              <div className="flex items-center gap-3 pt-4">
                <button 
                  type="button"
                  onClick={() => setShowPayModal(false)}
                  className="flex-1 py-4 text-sm font-bold text-slate-400 hover:text-slate-600 transition-all"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl text-sm font-black hover:bg-indigo-700 shadow-xl shadow-indigo-500/20 transition-all"
                >
                  Record Receipt
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

