                  className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-50 transition-all border border-transparent"
                >
                  Discard
                </button>
                <button 
                  type="submit"
                  className="px-10 py-3 rounded-xl bg-green-600 text-white font-bold hover:bg-green-700 transition-all shadow-lg shadow-green-500/20"
                >
