    const match = grade.match(/\d+/);
    return match ? `G${match[0]}` : grade.substring(0, 2).toUpperCase();
  };

  const initialFormData = {
    name: '', 
    fatherName: '', 
    phone: '', 
    grade: GRADES[0], 
