import React from 'react';
import { 
  Calendar, 
  Search, 
  ArrowRight, 
  Wallet,
  History,
  Printer,
  AlertCircle,
  X,
  CreditCard
} from 'lucide-react';
import { Student, FeeRecord, PaymentStatus, PaymentMethod } from '../types';
import { MONTHS, GRADE_FEES } from '../constants';

interface FeeManagementProps {
  students: Student[];
  fees: FeeRecord[];
  onAddFee: (fee: Omit<FeeRecord, 'id'>) => void;
  onUpdateFee: (id: string, updates: Partial<FeeRecord>) => void;
  onShowReceipt: (feeId: string) => void;
  searchTerm: string;
}

const FeeManagement: React.FC<FeeManagementProps> = ({ 
  students, fees, onAddFee, onUpdateFee, onShowReceipt, searchTerm 
}) => {
  const [selectedStudent, setSelectedStudent] = React.useState<Student | null>(null);
  const [showPayModal, setShowPayModal] = React.useState(false);
  const [payTargetMonth, setPayTargetMonth] = React.useState<string>(MONTHS[new Date().getMonth()]);
  const [payAmount, setPayAmount] = React.useState<number>(0);
  const [payMethod, setPayMethod] = React.useState<PaymentMethod>(PaymentMethod.CASH);
  const [payRemarks, setPayRemarks] = React.useState('');
  const [error, setError] = React.useState<string | null>(null);

  const filteredStudents = students.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.rollNumber.includes(searchTerm)
  );

  const getStudentStats = (studentId: string) => {
    const studentFees = fees.filter(f => f.studentId === studentId);
    const totalDue = studentFees.reduce((sum, f) => sum + f.totalAmount, 0);
    const totalPaid = studentFees.reduce((sum, f) => sum + f.paidAmount, 0);
    const balance = totalDue - totalPaid;
    return { totalDue, totalPaid, balance, count: studentFees.length };
  };

  const handleOpenPayModal = (student: Student, month?: string, remaining?: number) => {
    const standardFee = student.monthlyFee || GRADE_FEES[student.grade] || 2500;
    setSelectedStudent(student);
    setPayTargetMonth(month || MONTHS[new Date().getMonth()]);
    setPayAmount(remaining !== undefined ? remaining : standardFee);
    setPayRemarks('');
    setError(null);
    setShowPayModal(true);
  };

  const handleProcessPayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStudent) return;

    const existingFee = fees.find(f => f.studentId === selectedStudent.id && f.month === payTargetMonth);

    if (existingFee) {
      if (existingFee.status === PaymentStatus.PAID) {
        setError("Month is already paid.");
        return;
      }

      const newPaidAmount = existingFee.paidAmount + payAmount;
      const newStatus = newPaidAmount >= existingFee.totalAmount ? PaymentStatus.PAID : PaymentStatus.PARTIAL;

      onUpdateFee(existingFee.id, {
        paidAmount: newPaidAmount,
        status: newStatus,
        remarks: payRemarks || existingFee.remarks,
        paymentDate: new Date().toISOString().split('T')[0]
      });
    } else {
      const standardFee = selectedStudent.monthlyFee || GRADE_FEES[selectedStudent.grade] || 2500;
      const status = payAmount >= standardFee ? PaymentStatus.PAID : payAmount > 0 ? PaymentStatus.PARTIAL : PaymentStatus.UNPAID;

      onAddFee({
        studentId: selectedStudent.id,
        month: payTargetMonth,
        year: new Date().getFullYear(),
        totalAmount: standardFee,
        paidAmount: payAmount,
        status,
        paymentDate: new Date().toISOString().split('T')[0],
        method: payMethod,
        remarks: payRemarks,
        receiptNumber: `RCP-${Math.floor(1000 + Math.random() * 9000)}`
      });
    }

    setShowPayModal(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800">Fee Management</h1>
          <p className="text-sm text-slate-500">Collect fees and track arrears.</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[700px]">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Student</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Status Indicators</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Balance</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredStudents.map((student) => {
                const stats = getStudentStats(student.id);
                return (
                  <tr key={student.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-9 h-9 rounded-xl bg-indigo-600 flex items-center justify-center font-bold text-white shadow-md shadow-indigo-100 shrink-0">
                          {student.name.charAt(0)}
                        </div>
                        <div className="min-w-0">
                          <p className="font-bold text-slate-800 text-sm truncate">{student.name}</p>
                          <p className="text-[10px] text-slate-400 font-bold">{student.rollNumber}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex justify-center -space-x-1.5">
                        {fees.filter(f => f.studentId === student.id).slice(0, 4).map((f) => (
                          <div 
                            key={f.id} 
                            className={`w-5 h-5 rounded-full border-2 border-white flex items-center justify-center text-[7px] font-black text-white ${
                              f.status === PaymentStatus.PAID ? 'bg-emerald-500' : 'bg-red-500'
                            }`}
                          >
                            {f.month.charAt(0)}
                          </div>
                        ))}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <span className={`text-sm font-black ${stats.balance > 0 ? 'text-red-500' : 'text-emerald-600'}`}>
                        Rs. {stats.balance.toLocaleString()}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center justify-center gap-2">
                        <button 
                          onClick={() => handleOpenPayModal(student)}
                          className="px-3 py-2 bg-indigo-600 text-white rounded-lg text-[10px] font-black uppercase hover:bg-indigo-700 transition-all shadow-sm"
                        >
                          Collect
                        </button>
                        <button 
                          onClick={() => setSelectedStudent(student)}
                          className="p-2 bg-slate-50 text-slate-400 rounded-lg hover:bg-slate-100 transition-all border border-slate-100"
                        >
                          <History size={14} />
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Full-width slide-over for mobile */}
      {selectedStudent && !showPayModal && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-end bg-slate-900/40 backdrop-blur-sm p-0 sm:p-4">
          <div className="bg-white h-[90vh] sm:h-full w-full max-w-xl rounded-t-[2.5rem] sm:rounded-[2rem] shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom sm:slide-in-from-right duration-300">
            <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center justify-between shrink-0">
              <div className="flex items-center gap-3">
